mapper.update:
UPDATE LEARN_LIST
   SET TITLE = #{dto.title},
       START_DATE = TO_DATE(#{dto.startDate}, 'YYYY-MM-DD'),
       END_DATE = TO_DATE(SUBSTR(REPLACE(#{dto.deadline}, 'T', ' '), 1, 10), 'YYYY-MM-DD')
 WHERE CLASS_ID = #{classId}
   AND TEACHER_ID = #{teacherId}
   AND LEARN_LIST_ID = (
       SELECT LEARN_LIST_ID
       FROM LEARN_CONT
       WHERE LEARN_ID = #{learnId}
   )

UPDATE LEARN_CONT
   SET DELETE_YN = 1,
       DELETED_AT = SYSDATE
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID IN (
       SELECT LEARN_LIST_ID
       FROM LEARN_LIST
       WHERE CLASS_ID = #{classId}
         AND TEACHER_ID = #{teacherId}
   )

UPDATE LEARN_CONT
   SET DELETE_YN = 0,
       DELETED_AT = NULL
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID IN (
       SELECT LEARN_LIST_ID
       FROM LEARN_LIST
       WHERE CLASS_ID = #{classId}
         AND TEACHER_ID = #{teacherId}
   )

mapper.delete:
DELETE FROM LEARN_FBD
 WHERE PROGRESS_ID IN (
     SELECT LP.PROGRESS_ID
       FROM LEARN_PRO LP
      WHERE LP.LEARN_ID = #{learnId}
 )

DELETE FROM LEARN_CONT
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID = #{learnListId}
   AND NVL(DELETE_YN, 0) = 1

DELETE FROM LEARN_LIST
 WHERE LEARN_LIST_ID = #{learnListId}
   AND CLASS_ID = #{classId}
   AND TEACHER_ID = #{teacherId}
   AND NOT EXISTS (
        SELECT 1
          FROM LEARN_CONT
         WHERE LEARN_LIST_ID = #{learnListId}
   )
